scwin.f_Retrieve = async function () {
  if (!(await $c.gus.cfValidate($p, [tbl_search]))) return;
  if (ed_arrvlportDtmFrom.getValue() > ed_arrvlportDtmTo.getValue()) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_039); //시작일자가 종료일자 이전이어야 합니다.
    ed_arrvlportDtmFrom.focus();
    return;
  }
  $c.sbm.execute($p, sbm_ret);
};

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
  if (!ds_master.getModifiedIndex().length) return;
  let chkCount = 0;
  for (let i = 0; i < ds_master.getRowCount(); i++) {
    let rowJson = ds_master.getRowJSON(i);
    if (rowJson.inOdrChk == 1 || rowJson.outOdrChk == 1) {
      // 체크 박스 선택 했을 때 
      chkCount++;
    }
  }
  if (chkCount == 0) {
    await $c.gus.cfAlertMsg($p, "선택된 건이 하나도 없습니다.\n확인해 주십시오.");
    return;
  }
  if (!(await scwin.f_Check())) return;
  let ret = await $c.win.confirm($p, "저장하시겠습니까?");
  if (!ret) return;
  $c.sbm.execute($p, sbm_save);
};

//-------------------------------------------------------------------------
// 화면 입력 값 유효성 체크 ( 입력값 셋팅 : 모선. 항차 셋팅 ) 
//-------------------------------------------------------------------------
scwin.f_Check = async function () {
  // DPCT 냉동 컨테이너 매출 등록 유효성 체크 
  for (let i = 0; i < ds_master.getRowCount(); i++) {
    let rowJson = ds_master.getRowJSON(i);
    if (rowJson.inOdrChk == 1 || rowJson.outOdrChk == 1) {
      //  체크 박스 선택 했을 때 
      // PLUG IN OR PLUG OUT  필수 (둘다 없을 경우)
      if (rowJson.pluginDt == "" && rowJson.plugoutDt == "") {
        await $c.gus.cfAlertMsg($p, i + 1 + "번째 항의 PLUG IN과 PLUG OUT은 필수 입력 사항입니다.\n자동 선택 해제 처리 합니다.");
        ds_master.setCellData(i, "inOdrChk", "0");
        ds_master.setCellData(i, "outOdrChk", "0");
        return false;
      }

      // PLUG IN만 있을 경우, 반출오더번호 NULL로 셋팅(화주매출 생성 안되도록)
      if (rowJson.pluginDt != "" && rowJson.plugoutDt == "") {
        ds_master.setCellData(i, "outOdrNo", "");
      }

      // PLUG OUT만 있을 경우, 반입오더번호 NULL로 셋팅(선사매출 생성 안되도록)
      if (rowJson.pluginDt == "" && rowJson.plugoutDt != "") {
        ds_master.setCellData(i, "inOdrNo", "");
      }
    }
    if (rowJson.inOdrChk == 1) {
      //  체크 박스 선택 했을 때 
      //반입오더 매출 확정구분코드가 "1"보다 클경우("미확정"이 아닐경우) 수정불가능 체크 해제
      if (rowJson.inOdrDcsnClsCd > 1) {
        await $c.gus.cfAlertMsg($p, i + 1 + "번째 항의 반입오더 매출이 미확정이 아닙니다.\n자동 선택 해제 처리 합니다.");
        ds_master.setCellData(i, "inOdrChk", "0");
        return false;
      }
    }
    if (rowJson.outOdrChk == 1) {
      //  체크 박스 선택 했을 때 
      //반출오더 매출 확정구분코드가 "1"보다 클경우("미확정"이 아닐경우) 수정불가능 체크 해제
      if (rowJson.outOdrDcsnClsCd > 1) {
        await $c.gus.cfAlertMsg($p, i + 1 + "번째 항의 반출오더 매출이 미확정이 아닙니다.\n자동 선택 해제 처리 합니다.");
        ds_master.setCellData(i, "outOdrChk", "0");
        return false;
      }
    }
  }
  return true;
};

