scwin.grd_master_onbeforeedit = function (rowIndex, columnIndex, value) {
  scwin.olddata = value;
};
scwin.grd_master_onafteredit = async function (rowIndex, columnIndex, value) {
  let colid = ds_master.getColumnID(columnIndex);
  let rowJson = ds_master.getRowJSON(rowIndex);
  if (colid == "plugoutDt" || colid == "pluginDt") {
    // 반입오더 매출일수
    if (!(rowJson.pluginDt == "") && !(rowJson.applyDt == "")) {
      ds_master.setCellData(rowIndex, "inOdrSellDay", scwin.getOffsetDate(rowJson.applyDt + "00", rowJson.pluginDt + "00"));
    }

    // 반출오더 매출일수
    if (!(rowJson.plugoutDt == "") && !(rowJson.applyDt == "")) {
      ds_master.setCellData(rowIndex, "outOdrSellDay", scwin.getOffsetDate(rowJson.plugoutDt + "00", rowJson.applyDt + "00"));
    }

    // 총 장치일수(PLUGOUT - PLUGIN)
    if (!(rowJson.pluginDt == "") && !(rowJson.plugoutDt == "")) {
      ds_master.setCellData(rowIndex, "totDay", scwin.getOffsetDate(rowJson.plugoutDt + "00", rowJson.pluginDt + "00"));
    }

    // PLUGIN이 수정되었을 경우
    if (colid == "pluginDt") {
      if (rowJson.pluginDt != scwin.olddata) {
        ds_master.setCellData(rowIndex, "pluginModId", scwin.regId);
      }
    }

    // PLUGOUT이 수정되었을 경우
    if (colid == "plugoutDt") {
      if (rowJson.plugoutDt != scwin.olddata) {
        ds_master.setCellData(rowIndex, "plugoutModId", scwin.regId);
      }
    }
  }

  // 적용일시 수정시
  if (colid == "applyDt") {
    // 반입/반출 미확정 체크
    if (rowJson.inOdrDcsnClsCd > 1 || rowJson.outOdrDcsnClsCd > 1) {
      await $c.gus.cfAlertMsg($p, rowIndex + 1 + "번째 항의 적용일시는 반입오더 or 반출오더가 미확정이 아닐경우 수정하실수 없습니다.");
      ds_master.setCellData(rowIndex, "applyDt", scwin.olddata);
      return true;
    }

    // 적용일시 범위 체크 (plugin < apply < plugout)
    if (rowJson.pluginDt != "" && rowJson.plugoutDt != "") {
      if (rowJson.applyDt > rowJson.plugoutDt || rowJson.applyDt < rowJson.pluginDt) {
        await $c.gus.cfAlertMsg($p, "적용일시는 PLUGIN보다 크고 PLUGOUT보다 작아야합니다.");
        ds_master.setCellData(rowIndex, "applyDt", scwin.olddata);
        return true;
      }
    }

    // 반입오더 매출일수(적용일시 - PLUGIN)
    if (!(rowJson.pluginDt == "")) {
      if (rowJson.pluginDt == rowJson.applyDt) {
        ds_master.setCellData(rowIndex, "inOdrSellDay", 0);
      } else {
        ds_master.setCellData(rowIndex, "inOdrSellDay", scwin.getOffsetDate(rowJson.applyDt + "00", rowJson.pluginDt + "00"));
      }
    }

    // 반출오더 매출일수(PLUGOUT - 적용일시)
    if (!(rowJson.plugoutDt == "")) {
      ds_master.setCellData(rowIndex, "outOdrSellDay", scwin.getOffsetDate(rowJson.plugoutDt + "00", rowJson.applyDt + "00"));
    }
  }

  // 반입오더 매출일수 수정시
  if (colid == "inOdrSellDay") {
    // 미확정 체크
    if (rowJson.inOdrDcsnClsCd > 1 || rowJson.outOdrDcsnClsCd > 1) {
      await $c.gus.cfAlertMsg($p, rowIndex + 1 + "번째 항의 반입오더 매출일수는 반입오더 or 반출오더가 미확정이 아닐경우 수정하실수 없습니다.");
      ds_master.setCellData(rowIndex, "inOdrSellDay", scwin.olddata);
      return true;
    }

    // 마이너스 입력 체크
    if (rowJson.inOdrSellDay < 0) {
      await $c.gus.cfAlertMsg($p, "반입오더 매출일수를 잘못 입력하셨습니다.");
      ds_master.setCellData(rowIndex, "inOdrSellDay", scwin.olddata);
      return true;
    }

    // 적용일시 변경
    if (!(rowJson.pluginDt == "")) {
      if (rowJson.pluginDt != "" && rowJson.plugoutDt != "") {
        if (rowJson.applyDt > rowJson.plugoutDt || rowJson.applyDt < rowJson.pluginDt) {
          await $c.gus.cfAlertMsg($p, "적용일시는 PLUGIN보다 크고 PLUGOUT보다 작아야합니다.");
          ds_master.setCellData(rowIndex, "inOdrSellDay", scwin.olddata);
          return true;
        }
      }
      if (rowJson.inOdrSellDay == 0) {
        ds_master.setCellData(rowIndex, "applyDt", rowJson.pluginDt);
      } else {
        let minutes = rowJson.inOdrSellDay * 24 * 60 - 1;
        if (rowJson.plugoutDt != "") {
          if (scwin.updateDate(rowJson.pluginDt, minutes) > rowJson.plugoutDt) {
            await $c.gus.cfAlertMsg($p, "반입오더 매출일수를 다시 입력해주세요.");
            ds_master.setCellData(rowIndex, "inOdrSellDay", scwin.olddata);
            return true;
          }
        }
        ds_master.setCellData(rowIndex, "applyDt", scwin.updateDate(rowJson.pluginDt, minutes));
      }
    }

    // 반출오더 매출일수
    if (!(rowJson.plugoutDt == "") && !(ds_master.getCellData(rowIndex, "applyDt") == "")) {
      if (rowJson.plugoutDt == ds_master.getCellData(rowIndex, "applyDt")) {
        ds_master.setCellData(rowIndex, "outOdrSellDay", 0);
      } else {
        ds_master.setCellData(rowIndex, "outOdrSellDay", scwin.getOffsetDate(rowJson.plugoutDt + "00", ds_master.getCellData(rowIndex, "applyDt") + "00"));
      }
    }
  }

  // 반출오더 매출일수 수정시
  if (colid == "outOdrSellDay") {
    // 반입/반출 미확정일 경우 수정 불가
    if (rowJson.inOdrDcsnClsCd > 1 || rowJson.outOdrDcsnClsCd > 1) {
      await $c.gus.cfAlertMsg($p, rowIndex + 1 + "번째 항의 반출오더 매출일수는 반입오더 or 반출오더가 미확정이 아닐경우 수정하실수 없습니다.");
      ds_master.setCellData(rowIndex, "outOdrSellDay", scwin.olddata);
      return true;
    }

    // 음수 입력 시
    if (rowJson.outOdrSellDay < 0) {
      await $c.gus.cfAlertMsg($p, "반입오더 매출일수를 잘못 입력하셨습니다.");
      ds_master.setCellData(rowIndex, "outOdrSellDay", scwin.olddata);
      return true;
    }

    // 적용일시 계산 (PLUGOUT 기준)
    if (!(rowJson.plugoutDt == "")) {
      // 적용일시 범위 체크 (plugin < apply < plugout)
      if (rowJson.pluginDt != "" && rowJson.plugoutDt != "") {
        if (rowJson.applyDt > rowJson.plugoutDt || rowJson.applyDt < rowJson.pluginDt) {
          await $c.gus.cfAlertMsg($p, "적용일시는 PLUGIN보다 크고 PLUGOUT보다 작아야합니다.");
          ds_master.setCellData(rowIndex, "outOdrSellDay", scwin.olddata);
          return true;
        }
      }

      // 매출일수 0 → 적용일시 = plugoutDt
      if (rowJson.outOdrSellDay == 0) {
        ds_master.setCellData(rowIndex, "applyDt", rowJson.plugoutDt);
      } else {
        let minutes = rowJson.outOdrSellDay * 24 * 60 - 1;

        // 적용일시가 plugoutDt 이후가 되면 오류
        if (scwin.updateDate(rowJson.plugoutDt, -minutes) > rowJson.plugoutDt) {
          await $c.gus.cfAlertMsg($p, "반입오더 매출일수를 다시 입력해주세요.");
          ds_master.setCellData(rowIndex, "outOdrSellDay", scwin.olddata);
          return true;
        }
        ds_master.setCellData(rowIndex, "applyDt", scwin.updateDate(rowJson.plugoutDt, -minutes));
      }
    }

    // 반입오더 매출일수 = 적용일시 - PLUGIN
    if (!(rowJson.pluginDt == "") && !(rowJson.applyDt == "")) {
      ds_master.setCellData(rowIndex, "inOdrSellDay", scwin.getOffsetDate(rowJson.applyDt + "00", rowJson.pluginDt + "00"));
    }
  }
  if (colid == "applyDt") {
    if (ds_master.getModifiedIndex().length > 0) {
      grd_master.setColumnReadOnly("inOdrSellDay", true);
      grd_master.setColumnReadOnly("outOdrSellDay", true);
    }
  }
  if (colid == "inOdrSellDay") {
    if (ds_master.getModifiedIndex().length > 0) {
      grd_master.setColumnReadOnly("applyDt", true);
      grd_master.setColumnReadOnly("outOdrSellDay", true);
    }
  }
  if (colid == "outOdrSellDay") {
    if (ds_master.getModifiedIndex().length > 0) {
      grd_master.setColumnReadOnly("applyDt", true);
      grd_master.setColumnReadOnly("inOdrSellDay", true);
    }
  }
};
